/// Handles biometric authentication using local_auth
class BiometricAuthService {
  final LocalAuthentication _localAuth = LocalAuthentication();

  /// Check if device supports biometrics
  Future<bool> isBiometricAvailable() async {
    try {
      final canAuthenticateWithBiometrics = await _localAuth.canCheckBiometrics;
      final canAuthenticate =
          canAuthenticateWithBiometrics || await _localAuth.isDeviceSupported();
      return canAuthenticate;
    } on PlatformException catch (e) {
      debugPrint('Biometric availability check failed: $e');
      return false;
    }
  }

  /// Get list of available biometric types
  Future<List<BiometricType>> getAvailableBiometrics() async {
    try {
      return await _localAuth.getAvailableBiometrics();
    } on PlatformException catch (e) {
      debugPrint('Failed to get available biometrics: $e');
      return [];
    }
  }

  /// Authenticate using biometrics
  Future<BiometricAuthResult> authenticate({
    String reason = 'Authenticate to access your account',
  }) async {
    try {
      final isAvailable = await isBiometricAvailable();
      if (!isAvailable) {
        return BiometricAuthResult(
          success: false,
          error: BiometricError.notAvailable,
          message: 'Biometric authentication is not available on this device',
        );
      }

      final didAuthenticate = await _localAuth.authenticate(
        localizedReason: reason,
        options: const AuthenticationOptions(
          stickyAuth: true,
          biometricOnly: false, // Allow device PIN/password as fallback
          useErrorDialogs: true,
        ),
      );

      if (didAuthenticate) {
        return BiometricAuthResult(
          success: true,
          message: 'Authentication successful',
        );
      } else {
        return BiometricAuthResult(
          success: false,
          error: BiometricError.failed,
          message: 'Authentication failed',
        );
      }
    } on PlatformException catch (e) {
      BiometricError error;
      String message;

      switch (e.code) {
        case 'NotAvailable':
          error = BiometricError.notAvailable;
          message = 'Biometric authentication not available';
          break;
        case 'NotEnrolled':
          error = BiometricError.notEnrolled;
          message = 'No biometrics enrolled on this device';
          break;
        case 'LockedOut':
          error = BiometricError.lockedOut;
          message = 'Too many attempts. Biometric locked out.';
          break;
        case 'PermanentlyLockedOut':
          error = BiometricError.permanentlyLockedOut;
          message =
              'Biometric permanently locked. Use device password to unlock.';
          break;
        default:
          error = BiometricError.unknown;
          message = e.message ?? 'Unknown error occurred';
      }

      return BiometricAuthResult(
        success: false,
        error: error,
        message: message,
      );
    }
  }

  /// Cancel ongoing authentication
  Future<void> cancelAuthentication() async {
    await _localAuth.stopAuthentication();
  }
}

enum BiometricError {
  notAvailable,
  notEnrolled,
  lockedOut,
  permanentlyLockedOut,
  failed,
  unknown,
}

class BiometricAuthResult {
  final bool success;
  final BiometricError? error;
  final String message;

  BiometricAuthResult({
    required this.success,
    this.error,
    required this.message,
  });
}

