/// Home screen shown after successful authentication
class HomeScreen extends StatefulWidget {
  final String userId;
  final VoidCallback onLogout;

  const HomeScreen({
    super.key,
    required this.userId,
    required this.onLogout,
  });

  @override
  State<HomeScreen> createState() => _HomeScreenState();
}

class _HomeScreenState extends State<HomeScreen> {
  String? _authToken;
  bool _biometricEnabled = false;
  final BiometricAuthService _biometricService = BiometricAuthService();

  @override
  void initState() {
    super.initState();
    _loadSessionInfo();
  }

  Future<void> _loadSessionInfo() async {
    final token = await SecureSessionManager.getAuthToken();
    final biometricEnabled = await SecureSessionManager.isBiometricEnabled();
    setState(() {
      _authToken = token;
      _biometricEnabled = biometricEnabled;
    });
  }

  Future<void> _toggleBiometric() async {
    if (_biometricEnabled) {
      // Disable biometric - require biometric verification first
      final result = await _biometricService.authenticate(
        reason: 'Verify your identity to disable biometric login',
      );
      if (result.success) {
        await SecureSessionManager.clearSession();
        // Re-store credentials without biometric session
        await SecureSessionManager.storeUserCredentials(
          userId: widget.userId,
          authToken: _authToken ?? '',
        );
        setState(() {
          _biometricEnabled = false;
        });
        if (mounted) {
          ScaffoldMessenger.of(context).showSnackBar(
            const SnackBar(
              content: Text('Biometric login disabled'),
              backgroundColor: Colors.orange,
            ),
          );
        }
      }
    } else {
      // Enable biometric
      final result = await _biometricService.authenticate(
        reason: 'Verify your identity to enable biometric login',
      );
      if (result.success) {
        final sessionCreated = await SecureSessionManager.createSecureSession();
        if (sessionCreated) {
          setState(() {
            _biometricEnabled = true;
          });
          if (mounted) {
            ScaffoldMessenger.of(context).showSnackBar(
              const SnackBar(
                content: Text('Biometric login enabled!'),
                backgroundColor: Colors.green,
              ),
            );
          }
        }
      } else {
        if (mounted) {
          ScaffoldMessenger.of(context).showSnackBar(
            SnackBar(
              content: Text('Failed: ${result.message}'),
              backgroundColor: Colors.red,
            ),
          );
        }
      }
    }
  }

  Future<void> _performSecureAction() async {
    // Example: require biometric re-verification for sensitive actions
    final result = await _biometricService.authenticate(
      reason: 'Verify your identity for this sensitive action',
    );

    if (result.success) {
      final token = await SecureSessionManager.getAuthToken();
      if (mounted) {
        showDialog(
          context: context,
          builder: (context) => AlertDialog(
            icon: const Icon(Icons.check_circle, color: Colors.green, size: 48),
            title: const Text('Secure Action Completed'),
            content: Text(
              'Auth token retrieved successfully.\n'
              'Token prefix: ${token?.substring(0, 20) ?? "N/A"}...',
            ),
            actions: [
              FilledButton(
                onPressed: () => Navigator.of(context).pop(),
                child: const Text('OK'),
              ),
            ],
          ),
        );
      }
    } else {
      if (mounted) {
        ScaffoldMessenger.of(context).showSnackBar(
          SnackBar(
            content: Text('Verification failed: ${result.message}'),
            backgroundColor: Colors.red,
          ),
        );
      }
    }
  }

